// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/applications", wrapper.GetApplications)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/applications/{name}", wrapper.GetApplicationsName)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/applications/{name}/matrix", wrapper.GetApplicationsNameMatrix)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/applications/{name}/promotions", wrapper.GetApplicationsNamePromotions)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/applications/{name}/releases", wrapper.GetApplicationsNameReleases)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/audit", wrapper.GetAudit)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/diff", wrapper.GetDiff)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/environments", wrapper.GetEnvironments)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/promotions", wrapper.GetPromotions)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/promotions", wrapper.PostPromotions)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/promotions/{id}", wrapper.GetPromotionsID)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/promotions/{id}/approve", wrapper.PostPromotionsIDApprove)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/promotions/{id}/cancel", wrapper.PostPromotionsIDCancel)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/promotions/{id}/retry", wrapper.PostPromotionsIDRetry)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/releases", wrapper.GetReleases)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/targets", wrapper.GetTargets)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/targets/{name}/drift", wrapper.GetTargetsNameDrift)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/targets/{name}/health", wrapper.GetTargetsNameHealth)

	return m
}

